noncompliant:
# Noncompliant: Overriding to_json directly
class User < ApplicationRecord
  def to_json(options = {})
    {
      id: id,
      name: name,
      email: email
    }.to_json
  end
end

compliant:
# Compliant: Override as_json instead
class User < ApplicationRecord
  def as_json(options = {})
    {
      id: id,
      name: name,
      email: email
    }
  end
end
